type TechIcon = {
  name: string;
  hoverClass: string;
  svg: React.ReactNode;
};

type ToolChip = {
  name: string;
  svg: React.ReactNode;
};

function CategoryLabel({ label }: { label: string }) {
  return (
    <div className="flex items-center gap-3 mb-6">
      <div
        className="w-4 h-px bg-primary shrink-0"
        style={{
          boxShadow:
            "0 0 6px var(--color-primary), 0 0 14px color-mix(in oklch, var(--color-primary) 40%, transparent)",
        }}
      />
      <span className="text-[10px] font-bold tracking-[0.3em] uppercase text-primary/60">
        {label}
      </span>
    </div>
  );
}

function TechGrid({ items }: { items: TechIcon[] }) {
  return (
    <div className="flex flex-wrap gap-6 items-end">
      {items.map(({ name, hoverClass, svg }) => (
        <div key={name} className="flex flex-col items-center gap-2 group">
          <div
            className={`w-12 h-12 lg:w-14 lg:h-14 flex items-center justify-center text-base-content/20 ${hoverClass} transition-all duration-300`}
          >
            {svg}
          </div>
          <span className="text-[10px] font-semibold tracking-wide text-base-content/30 group-hover:text-base-content/60 transition-colors duration-300">
            {name}
          </span>
        </div>
      ))}
    </div>
  );
}

function ToolChipGroup({ title, items }: { title: string; items: ToolChip[] }) {
  return (
    <div className="flex flex-col gap-4">
      {/* En-tête catégorie */}
      <div className="flex items-center gap-3">
        <div
          className="w-1.5 h-1.5 rounded-full bg-primary shrink-0"
          style={{ boxShadow: "0 0 6px var(--color-primary)" }}
        />
        <span className="text-[10px] font-bold tracking-[0.35em] uppercase text-primary/60">
          {title}
        </span>
        <div className="flex-1 h-px bg-gradient-to-r from-primary/25 to-transparent" />
      </div>

      {/* Pills */}
      <div className="flex flex-wrap gap-2">
        {items.map(({ name, svg }) => (
          <span
            key={name}
            className="group/chip flex items-center gap-2 px-3 py-1.5 text-[11px] font-semibold rounded-full border border-base-content/10 bg-base-content/[0.03] text-base-content/50 hover:text-primary hover:border-primary/40 hover:bg-primary/[0.05] hover:shadow-[0_0_14px_color-mix(in_oklch,var(--color-primary)_12%,transparent)] transition-all duration-300 cursor-default"
          >
            <span className="shrink-0 text-base-content/30 group-hover/chip:text-primary transition-colors duration-300">
              {svg}
            </span>
            {name}
          </span>
        ))}
      </div>
    </div>
  );
}

